// src/pages/Artisan.jsx

import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { Container, Row, Col, Card, Form, Button } from "react-bootstrap";

function Artisan() {
  const { id } = useParams();

  const [artisan, setArtisan] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: "",
  });

  useEffect(() => {
    fetch(`http://localhost:3000/api/artisans/${id}`)
      .then((res) => res.json())
      .then((data) => setArtisan(data))
      .catch((error) => console.error(error));
  }, [id]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    fetch(`http://localhost:3000/api/artisans/${id}/contact`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(formData),
    })
      .then((res) => res.json())
      .then(() => {
        alert("Message envoyé avec succès");

        setFormData({
          name: "",
          email: "",
          subject: "",
          message: "",
        });
      })
      .catch((error) => console.error(error));
  };

  if (!artisan) {
    return (
      <Container className="py-5 text-center">
        <p>Chargement...</p>
      </Container>
    );
  }

  return (
    <Container className="py-5">
      <Card className="shadow border-0">
        <Row className="g-0">
          <Col md={5}>
            <Card.Img
              variant="top"
              src={artisan.image || "/images/default-artisan.jpg"}
              alt={artisan.name}
              className="h-100 object-fit-cover"
            />
          </Col>

          <Col md={7}>
            <Card.Body className="p-4">
              <Card.Title as="h1" className="mb-4">
                {artisan.name}
              </Card.Title>

              <p>
                <strong>Note :</strong>{" "}
                {"★".repeat(Math.round(artisan.note))}
                {"☆".repeat(5 - Math.round(artisan.note))}
              </p>

              <p>
                <strong>Spécialité :</strong> {artisan.specialty}
              </p>

              <p>
                <strong>Localisation :</strong> {artisan.location}
              </p>

              {artisan.website && (
                <p>
                  <strong>Site web :</strong>{" "}
                  <a
                    href={artisan.website}
                    target="_blank"
                    rel="noreferrer"
                  >
                    Visiter le site
                  </a>
                </p>
              )}

              <hr />

              <h2 className="h4">À propos</h2>

              <p>{artisan.about}</p>
            </Card.Body>
          </Col>
        </Row>
      </Card>

      <Card className="shadow border-0 mt-5">
        <Card.Body className="p-4">
          <h2 className="mb-4">Contacter cet artisan</h2>

          <Form onSubmit={handleSubmit}>
            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Nom</Form.Label>

                  <Form.Control
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    required
                  />
                </Form.Group>
              </Col>

              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Email</Form.Label>

                  <Form.Control
                    type="email"
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                  />
                </Form.Group>
              </Col>
            </Row>

            <Form.Group className="mb-3">
              <Form.Label>Objet</Form.Label>

              <Form.Control
                type="text"
                name="subject"
                value={formData.subject}
                onChange={handleChange}
                required
              />
            </Form.Group>

            <Form.Group className="mb-4">
              <Form.Label>Message</Form.Label>

              <Form.Control
                as="textarea"
                rows={5}
                name="message"
                value={formData.message}
                onChange={handleChange}
                required
              />
            </Form.Group>

            <Button variant="primary" type="submit">
              Envoyer le message
            </Button>
          </Form>
        </Card.Body>
      </Card>
    </Container>
  );
}

export default Artisan;
